using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== SOLUTION STRUCTURE ===");
var projects = new List<(string name, string path, bool succeeded)>();
build.VisitAllChildren<Project>(p => {
    projects.Add((p.Name, p.ProjectFile, p.Succeeded));
});
foreach (var g in projects.GroupBy(p => p.name))
{
    var any = g.First();
    Console.WriteLine($"  Project: {any.name} | Path: {any.path} | Succeeded: {g.All(x => x.succeeded)}");
}

Console.WriteLine("\n=== ALL ERRORS ===");
var errors = new List<(string project, string code, string file, int line, int col, string message)>();
build.VisitAllChildren<Error>(e => {
    var proj = "";
    var node = e.Parent;
    while (node != null)
    {
        if (node is Project p) { proj = p.Name; break; }
        node = node.Parent;
    }
    errors.Add((proj, e.Code, e.File, e.LineNumber, e.ColumnNumber, e.Text));
    Console.WriteLine($"  [{proj}] {e.Code}: {e.File}({e.LineNumber},{e.ColumnNumber}): {e.Text}");
});

Console.WriteLine("\n=== ALL WARNINGS ===");
build.VisitAllChildren<Warning>(w => {
    var proj = "";
    var node = w.Parent;
    while (node != null)
    {
        if (node is Project p) { proj = p.Name; break; }
        node = node.Parent;
    }
    Console.WriteLine($"  [{proj}] {w.Code}: {w.File}({w.LineNumber},{w.ColumnNumber}): {w.Text}");
});

Console.WriteLine("\n=== PROJECT DEPENDENCY GRAPH ===");
build.VisitAllChildren<Project>(p => {
    var deps = new List<string>();
    p.VisitAllChildren<Project>(child => {
        if (child != p) deps.Add(child.Name);
    });
    if (deps.Any())
        Console.WriteLine($"  {p.Name} -> [{string.Join(", ", deps.Distinct())}]");
});

Console.WriteLine($"\n=== BUILD RESULT: {(build.Succeeded ? "SUCCESS" : "FAILED")} ===");
Console.WriteLine($"Total errors: {errors.Count}");
