using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;
using System.Linq;

var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

// Detailed error info with context
Console.WriteLine("=== DETAILED ERROR ANALYSIS ===\n");

var errorsByProject = new Dictionary<string, List<(string code, string file, int line, int col, string text, string subcategory)>>();

build.VisitAllChildren<Error>(e => {
    var proj = "";
    var node = e.Parent;
    while (node != null)
    {
        if (node is Project p) { proj = p.Name; break; }
        node = node.Parent;
    }
    if (!errorsByProject.ContainsKey(proj))
        errorsByProject[proj] = new();
    errorsByProject[proj].Add((e.Code ?? "", e.File ?? "", e.LineNumber, e.ColumnNumber, e.Text ?? "", e.Subcategory ?? ""));
});

foreach (var kvp in errorsByProject)
{
    Console.WriteLine($"PROJECT: {kvp.Key}");
    foreach (var e in kvp.Value)
    {
        Console.WriteLine($"  Error {e.code}");
        Console.WriteLine($"    File: {e.file}");
        Console.WriteLine($"    Line: {e.line}, Col: {e.col}");
        Console.WriteLine($"    Message: {e.text}");
        Console.WriteLine($"    Subcategory: {e.subcategory}");
        Console.WriteLine();
    }
}

// Check which projects failed
Console.WriteLine("=== PROJECT BUILD OUTCOMES ===\n");
var projectOutcomes = new Dictionary<string, bool>();
build.VisitAllChildren<Project>(p => {
    // Only look at actual build targets (not restore etc)
    var targetNames = new List<string>();
    p.VisitAllChildren<Target>(t => targetNames.Add(t.Name));

    var hasErrors = false;
    p.VisitAllChildren<Error>(e => hasErrors = true);

    if (!projectOutcomes.ContainsKey(p.Name) || hasErrors)
        projectOutcomes[p.Name] = !hasErrors;
});

foreach (var kvp in projectOutcomes.OrderBy(x => x.Key))
{
    Console.WriteLine($"  {kvp.Key}: {(kvp.Value ? "OK" : "FAILED")}");
}

// Check project references to determine dependency chain
Console.WriteLine("\n=== DEPENDENCY CHAIN ===\n");
Console.WriteLine("  Api.csproj -> Services.csproj -> Core.csproj");
Console.WriteLine("  Api.csproj -> Core.csproj");

// Check if there were any cascading errors in Api due to Services failure
Console.WriteLine("\n=== CASCADING FAILURE ANALYSIS ===\n");
var apiErrors = new List<string>();
var coreErrors = new List<string>();
build.VisitAllChildren<Error>(e => {
    var proj = "";
    var node = e.Parent;
    while (node != null)
    {
        if (node is Project p) { proj = p.Name; break; }
        node = node.Parent;
    }
    if (proj == "Api.csproj") apiErrors.Add(e.Text ?? "");
    if (proj == "Core.csproj") coreErrors.Add(e.Text ?? "");
});

Console.WriteLine($"  Core.csproj errors: {coreErrors.Count}");
Console.WriteLine($"  Api.csproj errors: {apiErrors.Count}");
Console.WriteLine($"  Services.csproj errors: {errorsByProject.GetValueOrDefault("Services.csproj")?.Count ?? 0}");

// Check for MSB error codes (dependency failures)
Console.WriteLine("\n=== MSB/NU ERRORS (infrastructure) ===\n");
build.VisitAllChildren<Error>(e => {
    if ((e.Code ?? "").StartsWith("MSB") || (e.Code ?? "").StartsWith("NU"))
    {
        Console.WriteLine($"  {e.Code}: {e.Text}");
    }
});

// Check for failed project references 
Console.WriteLine("\n=== FAILED TARGET DETAILS ===\n");
build.VisitAllChildren<Target>(t => {
    if (t.Name == "ResolveProjectReferences" || t.Name == "Build")
    {
        var proj = "";
        var node = t.Parent;
        while (node != null)
        {
            if (node is Project p) { proj = p.Name; break; }
            node = node.Parent;
        }
        var hasErrors = false;
        t.VisitAllChildren<Error>(e => hasErrors = true);
        if (hasErrors)
            Console.WriteLine($"  {proj} / {t.Name} - FAILED");
    }
});
